  21: [1, 1, 1, 1], 22: [0, 2, 1, 1], 23: [0, 2, 2, 0], 24: [0, 2, 0, 2],
  25: [0, 1, 2, 1], 26: [0, 1, 1, 2], 27: [0, 1, 3, 0], 28: [0, 1, 0, 3],
  29: [0, 0, 3, 1], 30: [0, 0, 2, 2], 31: [0, 0, 1, 3], 32: [0, 3, 1, 0],
  33: [0, 3, 0, 1], 34: [1, 0, 1, 2], 35: [1, 0, 2, 1]
