WRATHS_5E.forEach(w => { w.sig = WRATH_SIGS[w.num] })
WRATHS_5E.sort((a, b) => a.num - b.num)

export const WRATHS_BY_ID = Object.fromEntries(WRATHS_5E.map(w => [w.id, w]))
export const WRATH_BY_SIG = bySignature(WRATHS_5E, w => w.sig)
